import re

def recover_use_case(code_evidence):
    actor = code_evidence["actor"]
    api_path_hints = code_evidence["api_path_hints"]
    test_path_hints = code_evidence["test_path_hints"]

    use_case_name = ""
    description = ""
    main_flow = []
    confidence = 0.0

    # Extract use case name from API path hints
    api_paths = re.findall(r"/([^/]+)", "/".join(api_path_hints))
    for path in api_paths:
        if "create" in path or "add" in path or "register" in path or "save" in path:
            use_case_name += f"Create {path.replace('_', ' ').title()} "
        elif "view" in path and re.search(r"/\d+$", path):
            use_case_name += f"View {path.replace('_', ' ').title()} detail "
        elif "list" in path or "search" in path:
            use_case_name += f"List/Search/View {path.replace('_', ' ').title()} "

    # Extract description from test path hints
    for path in test_path_hints:
        if "create" in path or "add" in path or "register" in path or "save" in path:
            description += f"Creates a new {path.replace('_', ' ').title()} record. "
        elif "view" in path and re.search(r"/\d+$", path):
            description += f"Views the detail of a {path.replace('_', ' ').title()} record. "
        elif "list" in path or "search" in path:
            description += f"Lists/searches for {path.replace('_', ' ').title()} records. "

    # Extract main flow from API and test paths
    api_paths = re.findall(r"/([^/]+)", "/".join(api_path_hints))
    test_paths = re.findall(r"/([^/]+)", "/".join(test_path_hints))
    for path in api_paths + test_paths:
        if "create" in path or "add" in path or "register" in path or "save" in path:
            main_flow.append(f"Create {path.replace('_', ' ').title()} record")
        elif "view" in path and re.search(r"/\d+$", path):
            main_flow.append(f"View {path.replace('_', ' ').title()} detail")
        elif "list" in path or "search" in path:
            main_flow.append(f"List/Search/View {path.replace('_', ' ').title()} records")

    # Assign confidence score based on the number of matching paths
    confidence = len(api_paths) + len(test_paths) / (len(api_paths) + len(test_paths))

    return {
        "actor": actor,
        "use_case_name": use_case_name.strip(),
        "description": description.strip(),
